// src/components/CourseCard.jsx
import React from 'react';

const CourseCard = () => {
  return (
    <div style={{
      border: '1px solid #ccc',
      borderRadius: '10px',
      padding: '20px',
      textAlign: 'center',
      background: 'white',
      boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
    }}>
      <div style={{ fontSize: '2rem' }}>📚</div>
      <h3>Course Name</h3>
      <p>Branch: CSE</p>
      <p>Semester: 3</p>
      <button style={{
        background: '#4f46e5',
        color: 'white',
        border: 'none',
        padding: '10px 20px',
        borderRadius: '5px',
        cursor: 'pointer',
        marginTop: '10px'
      }}>
        View Details
      </button>
    </div>
  );
};

export default CourseCard;
